import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';

function Navbar() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const { theme, toggleTheme } = useTheme();

  const getInitials = (name) => {
    if (!name) return '?';
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="cloud-logo">
          <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M6.5 19C3.46243 19 1 16.5376 1 13.5C1 10.4624 3.46243 8 6.5 8C6.67034 8 6.8382 8.00748 7.00356 8.02208C7.64506 5.12483 10.1909 3 13.1632 3C16.0387 3 18.4284 5.02887 18.8288 7.83419C21.3621 8.0549 23 9.86934 23 12.1111C23 14.6319 21.0148 16.7 18.5 16.9V21H6.5C9.53757 21 12 18.5376 12 15.5C12 12.4624 9.53757 10 6.5 10C6.35727 10 6.2156 10.0043 6.07529 10.0125C5.46574 7.20432 7.74557 5 10.5 5C11.6842 5 12.7787 5.4169 13.6 6.12396C13.862 5.88705 14.1612 5.68741 14.4893 5.53517C13.4631 4.41375 11.9943 3.75 10.5 3.75C7.6005 3.75 5.05915 5.33235 4.18208 7.84915C2.77424 8.56653 1.75 10.0491 1.75 11.75C1.75 14.3739 3.87614 16.5 6.5 16.5H18.5C17.1193 16.5 15.9147 15.7125 15.3098 14.5H6.5C8.98528 14.5 11 12.4853 11 10C11 7.51472 8.98528 5.5 6.5 5.5C4.01472 5.5 2 7.51472 2 10C2 12.4853 4.01472 14.5 6.5 14.5H15.25C16.2165 14.5 17 13.7165 17 12.75C17 11.7835 16.2165 11 15.25 11C14.2835 11 13.5 11.7835 13.5 12.75C13.5 13.7165 14.2835 14.5 15.25 14.5H18.5C20.9853 14.5 23 12.4853 23 10C23 7.51472 20.9853 5.5 18.5 5.5C17.1193 5.5 15.9147 6.28749 15.3098 7.5H6.5C5.28349 7.5 4.25 8.53349 4.25 9.75C4.25 10.9665 5.28349 12 6.5 12C7.71651 12 8.75 10.9665 8.75 9.75C8.75 8.53349 7.71651 7.5 6.5 7.5C8.98528 7.5 11 9.51472 11 12C11 14.4853 8.98528 16.5 6.5 16.5H6.5Z" fill="var(--primary)"/>
          </svg>
        </div>
      </div>
      <div className="navbar-right">
        {user ? (
          <>
            <button
              className="navbar-btn"
              onClick={() => navigate('/settings')}
              title="Manage Account"
            >
              <i className="fa-solid fa-user-gear"></i>
              <span>Manage Account</span>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="User Profile"
            >
              <div className="user-avatar">
                {getInitials(user.fullName)}
              </div>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="Settings"
            >
              <i className="fa-solid fa-gear"></i>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="navbar-btn"
              onClick={logout}
              title="Sign Out"
            >
              <i className="fa-solid fa-right-from-bracket"></i>
              <span>Sign Out</span>
            </button>
          </>
        ) : (
          <>
            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="btn btn-primary"
              onClick={() => navigate('/auth')}
              style={{ borderRadius: '20px', padding: '6px 18px', fontSize: '13px', fontWeight: 500 }}
            >
              <i className="fa-solid fa-user" style={{ fontSize: '13px' }}></i>
              <span>Sign In</span>
            </button>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
